import {
  AnyDocumentIndexConfig,
  DocumentBase,
  DocumentClient,
  DocumentConfigIndexes,
  DocumentIndex,
  LoaderNames,
} from '../index.ts';

import { TObject, TProperties, Type } from '@sinclair/typebox';
import * as Codegen from '@sinclair/typebox-codegen';
import { TypeCheck } from '@utils/type-check.ts';
import { Db } from 'mongodb';
import { captureStackTrace, Compute, invariant, Merge } from 'powership';
import { EntityLoader } from './entity-loader.ts';

// prettier-ignore
export interface EntityLoaders<
  InputType extends TObject,
  Indexes extends DocumentConfigIndexes<DocumentBase>,
> {
  createOne: EntityLoader.Loader<'createOne', InputType, Indexes> extends (param: infer Param) => infer Result ? (params: Compute<Param>) => Result: never;
  findById: EntityLoader.Loader<'findById', InputType, Indexes> extends (param: infer Param) => infer Result ? (params: Compute<Param>) => Result: never;
  findMany: EntityLoader.Loader<'findMany', InputType, Indexes> extends (param: infer Param) => infer Result ? (params: Compute<Param>) => Result: never;
  findOne: EntityLoader.Loader<'findOne', InputType, Indexes> extends (param: infer Param) => infer Result ? (params: Compute<Param>) => Result: never;
  updateOne: EntityLoader.Loader<'updateOne', InputType, Indexes> extends (param: infer Param) => infer Result ? (params: Compute<Param>) => Result: never;
  updateMany: EntityLoader.Loader<'updateMany', InputType, Indexes> extends (param: infer Param) => infer Result ? (params: Compute<Param>) => Result: never;
  deleteOne: EntityLoader.Loader<'deleteOne', InputType, Indexes> extends (param: infer Param) => infer Result ? (params: Compute<Param>) => Result: never;
  deleteMany: EntityLoader.Loader<'deleteMany', InputType, Indexes> extends (param: infer Param) => infer Result ? (params: Compute<Param>) => Result: never;
  paginate: EntityLoader.Loader<'paginate', InputType, Indexes> extends (param: infer Param) => infer Result ? (params: Compute<Param>) => Result: never;
}

// prettier-ignore
export interface TEntity<
  Object extends TObject,
  Indexes extends DocumentConfigIndexes<DatabaseDocumentType<Object>>
> extends EntityLoaders<Object, Indexes> {
  readonly $inputType: Object;
  readonly $name: string;
  readonly $indexes: Indexes;
  readonly type: TObject
  checkInput: TypeCheck<Object>['parse'];
  setupDatabase(): Promise<void>
}

export namespace Entity {
  const ULID_TYPE = Type.String({
    pattern: '^[0123456789ABCDEFGHJKMNPQRSTVWXYZ]{26}$',
  });

  function getDatabaseFields(
    indexConfig: AnyDocumentIndexConfig
  ) {
    const { indexes } = indexConfig;
    const entity = indexConfig.entity.toLowerCase();
    const { INDEX_PART_SEP, RELATION_PRECEDES } = DocumentIndex;

    return indexes.reduce((acc: any, index) => {
      const PKRegex = (() => {
        if (index.relatedTo) {
          const relName = index.relatedTo.toLowerCase();
          return `^${relName}${INDEX_PART_SEP}${index.name}${INDEX_PART_SEP}[^${RELATION_PRECEDES}]*${RELATION_PRECEDES}${entity}${INDEX_PART_SEP}.*`;
        }
        return `^${entity}${INDEX_PART_SEP}${index.name}${INDEX_PART_SEP}.*`;
      })();

      const PKName = DocumentIndex.parseFieldName(index.name, 'PK');

